const body = ($json.body && typeof $json.body === 'object') ? $json.body : $json;
const required = ['schema', 'workspace_id', 'run_id', 'stage_id', 'source_bucket', 'source_key', 'source_entity_id', 'source_artifact_id', 'manifest_prefix', 'workspace_prefix', 'target_prefix', 'save_path'];
for (const key of required) {
  if (body[key] === undefined || body[key] === null || String(body[key]).trim() === '') {
    throw new Error(`Missing required Beehive control envelope field: ${key}`);
  }
}
if (body.schema !== 'beehive.s3_control_envelope.v1') {
  throw new Error(`Unsupported control envelope schema: ${body.schema}`);
}
return [{ json: body }];

const control = $('Read control JSON body').first().json;
const source = $json.source_json || $json.json || $json;
const compactRun = control.run_id.replace(/[^a-zA-Z0-9]/g, '').slice(0, 16);
const outputArtifactId = `smoke_output_${compactRun}_${control.source_artifact_id}`.slice(0, 180);
const outputKey = `${control.target_prefix.replace(/\/+$/, '')}/${outputArtifactId}.json`;
const canonical = source.canonical_tag_ru || source.raw_article?.canonical_tag_ru || source.tag_id || control.source_entity_id;
const output = {
  schema: 'beehive.s3_smoke_output.v1',
  smoke_status: 'ok',
  created_at: new Date().toISOString(),
  beehive_run_id: control.run_id,
  source: {
    bucket: control.source_bucket,
    key: control.source_key,
    version_id: control.source_version_id || null,
    etag: control.source_etag || null,
    entity_id: control.source_entity_id,
    artifact_id: control.source_artifact_id
  },
  entity_id: control.source_entity_id,
  artifact_id: outputArtifactId,
  canonical_tag_ru: canonical,
  entity_type: source.entity_type || source.raw_article?.entity_type || null,
  preview_blocks: source.preview_blocks || []
};
const manifest = {
  schema: 'beehive.s3_artifact_manifest.v1',
  workspace_id: control.workspace_id,
  run_id: control.run_id,
  source: {
    bucket: control.source_bucket,
    key: control.source_key,
    version_id: control.source_version_id || null,
    etag: control.source_etag || null
  },
  status: 'success',
  outputs: [
    {
      artifact_id: outputArtifactId,
      entity_id: control.source_entity_id,
      relation_to_source: 'same_entity',
      bucket: control.source_bucket,
      key: outputKey,
      save_path: control.save_path,
      content_type: 'application/json',
      checksum_sha256: null,
      size: Buffer.byteLength(JSON.stringify(output), 'utf8')
    }
  ],
  created_at: new Date().toISOString()
};
const data = await this.helpers.prepareBinaryData(
  Buffer.from(JSON.stringify(output, null, 2), 'utf8'),
  `${outputArtifactId}.json`,
  'application/json'
);
return [{
  json: {
    ...control,
    output_bucket: control.source_bucket,
    output_key: outputKey,
    output_artifact_id: outputArtifactId,
    output_entity_id: control.source_entity_id,
    manifest
  },
  binary: { data }
}];
